mapper.select:
/* SQL ID : TkexamDAO.quizTkexamList 설 명 : 퀴즈응시목록 */ SELECT ROW_NUMBER() OVER(ORDER BY A.USERNM) AS LINE_NO , A.* FROM ( WITH DTL AS ( SELECT EXAM_DTL_ID FROM TB_LMS_EXAM_DTL WHERE DELYN = 'N' AND USEYN = 'Y' AND EXAM_BSC_ID = #{examBscId} ), TEAM AS ( SELECT EXAM_TRGTR.EXAM_DTL_ID , TEAM.TEAM_ID , TEAM.TEAMNM , TEAM_MBR.USER_ID , TEAM_MBR.LDRYN FROM TB_LMS_TEAM TEAM JOIN TB_LMS_EXAM_TRGTR EXAM_TRGTR ON TEAM.TEAM_ID = EXAM_TRGTR.TEAM_ID JOIN TB_LMS_TEAM_MBR TEAM_MBR ON TEAM.TEAM_ID = TEAM_MBR.TEAM_ID WHERE TEAM.TEAM_CPST_CMPTNYN = 'Y' AND EXAM_TRGTR.EXAM_DTL_ID IN (SELECT EXAM_DTL_ID FROM DTL) ), TKEXAM AS ( SELECT TKEXAM.EXAM_DTL_ID , TKEXAM.TKEXAM_ID , TKEXAM.USER_ID , TKEXAM.TKEXAM_CNT , TKEXAM.TKEXAM_SDTTM , TKEXAM.TKEXAM_EDTTM , TKEXAM.TKEXAM_CMPTNYN , TKEXAM_RSLT.EVLYN , TKEXAM_RSLT.TOT_SCR , TKEXAM.RETKEXAM_YN , QS.QUIZ_SCR FROM TB_LMS_TKEXAM TKEXAM LEFT JOIN TB_LMS_TKEXAM_RSLT TKEXAM_RSLT ON TKEXAM.TKEXAM_ID = TKEXAM_RSLT.TKEXAM_ID AND TKEXAM.USER_ID = TKEXAM_RSLT.USER_ID LEFT JOIN ( SELECT ANSW.USER_ID , EXAMPPR.TKEXAM_ID , SUM(ANSW.SCR) AS QUIZ_SCR FROM TB_LMS_TKEXAM_ANSW_SHT ANSW JOIN TB_LMS_EXAMPPR EXAMPPR ON ANSW.EXAMPPR_ID = EXAMPPR.EXAMPPR_ID AND ANSW.USER_ID = EXAMPPR.USER_ID GROUP BY ANSW.USER_ID, EXAMPPR.TKEXAM_ID ) QS ON TKEXAM.TKEXAM_ID = QS.TKEXAM_ID AND TKEXAM.USER_ID = QS.USER_ID WHERE TKEXAM.DELYN = 'N' AND TKEXAM.EXAM_DTL_ID IN (SELECT EXAM_DTL_ID FROM DTL) ) SELECT ATNDLC.SBJCT_ID , TM.TEAM_ID , TM.TEAMNM , NVL((SELECT DEPTNM FROM TB_LMS_DEPT WHERE ORG_ID = USR.ORG_ID AND DEPT_ID = USR.DEPT_ID),'-') AS DEPTNM , NVL(USR.STDNT_NO,'-') AS STDNT_NO , (SELECT CNTCT FROM TB_LMS_USER_CNTCT WHERE CNTCT_TYCD = 'MBL_PHN' AND USER_ID = ATNDLC.USER_ID) AS MOBILE_NO , (SELECT CNTCT FROM TB_LMS_USER_CNTCT WHERE CNTCT_TYCD = 'INDV_EML' AND USER_ID = ATNDLC.USER_ID) AS EMAIL , ATNDLC.USER_ID , USR.USER_RPRS_ID , USR.USERNM , TM.LDRYN , CASE WHEN EXAM_BSC.EXAM_GBNCD = 'QUIZ_TEAM' THEN TM.EXAM_DTL_ID ELSE (SELECT EXAM_DTL_ID FROM DTL) END EXAM_DTL_ID , CASE WHEN EXAM_BSC.EXAM_GBNCD = 'QUIZ_TEAM' THEN TKEXAM_TEAM.TKEXAM_ID ELSE TKEXAM_INDI.TKEXAM_ID END AS TKEXAM_ID , NVL(CASE WHEN EXAM_BSC.EXAM_GBNCD = 'QUIZ_TEAM' THEN TKEXAM_TEAM.QUIZ_SCR ELSE TKEXAM_INDI.QUIZ_SCR END, 0) AS QUIZ_SCR , NVL(CASE WHEN EXAM_BSC.EXAM_GBNCD = 'QUIZ_TEAM' THEN TKEXAM_TEAM.TOT_SCR ELSE TKEXAM_INDI.TOT_SCR END, 0) AS TOT_SCR , CASE WHEN EXAM_BSC.EXAM_GBNCD = 'QUIZ_TEAM' THEN TKEXAM_TEAM.TKEXAM_SDTTM ELSE TKEXAM_INDI.TKEXAM_SDTTM END AS TKEXAM_SDTTM , CASE WHEN EXAM_BSC.EXAM_GBNCD = 'QUIZ_TEAM' THEN TKEXAM_TEAM.TKEXAM_EDTTM ELSE TKEXAM_INDI.TKEXAM_EDTTM END AS TKEXAM_EDTTM , NVL(CASE WHEN EXAM_BSC.EXAM_GBNCD = 'QUIZ_TEAM' THEN TKEXAM_TEAM.TKEXAM_CMPTNYN ELSE TKEXAM_INDI.TKEXAM_CMPTNYN END,'N') AS TKEXAM_CMPTNYN , NVL(CASE WHEN EXAM_BSC.EXAM_GBNCD = 'QUIZ_TEAM' THEN TKEXAM_TEAM.TKEXAM_CNT ELSE TKEXAM_INDI.TKEXAM_CNT END, 0) AS TKEXAM_CNT , NVL(CASE WHEN EXAM_BSC.EXAM_GBNCD = 'QUIZ_TEAM' THEN TKEXAM_TEAM.EVLYN ELSE TKEXAM_INDI.EVLYN END,'N') AS EVLYN , NVL(CASE WHEN EXAM_BSC.EXAM_GBNCD = 'QUIZ_TEAM' THEN TKEXAM_TEAM.RETKEXAM_YN ELSE TKEXAM_INDI.RETKEXAM_YN END,'N') AS RETKEXAM_YN FROM TB_LMS_ATNDLC ATNDLC JOIN TB_LMS_EXAM_BSC EXAM_BSC ON ATNDLC.SBJCT_ID = EXAM_BSC.SBJCT_ID AND EXAM_BSC.USEYN = 'Y' AND EXAM_BSC.DELYN = 'N' JOIN TB_LMS_USER USR ON ATNDLC.USER_ID = USR.USER_ID AND USR.USER_ID_STSCD = 'APRV_CMPTN' AND USR.USER_TYCD = 'STDNT' LEFT JOIN TEAM TM ON TM.USER_ID = ATNDLC.USER_ID LEFT JOIN TKEXAM TKEXAM_TEAM ON TKEXAM_TEAM.EXAM_DTL_ID = TM.EXAM_DTL_ID AND TKEXAM_TEAM.USER_ID = ATNDLC.USER_ID LEFT JOIN TKEXAM TKEXAM_INDI ON TKEXAM_INDI.USER_ID = ATNDLC.USER_ID WHERE ATNDLC.AUDITYN = 'N' AND ATNDLC.ATNDLC_STSCD = 'ATNDLC' AND EXAM_BSC.EXAM_BSC_ID = #{examBscId} ) A
AND ( A.TKEXAM_CMPTNYN = #{tkexamCmptnyn} OR A.TKEXAM_SDTTM IS NOT NULL )
AND A.TKEXAM_CMPTNYN = #{tkexamCmptnyn}
AND A.EVLYN = #{evlyn}
AND ( LOWER(A.DEPTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.STDNT_NO) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )

mapper.update:
/* SQL ID : TkexamDAO.userListRetkexamSetting 설 명 : 사용자목록재응시설정 */ MERGE INTO TB_LMS_TKEXAM TKEXAM USING (
SELECT #{item.subParam} AS TKEXAM_ID , #{item.examDtlId} AS EXAM_DTL_ID , #{item.userId} AS USER_ID , #{item.reexamyn} AS RETKEXAM_YN , 0 AS TKEXAM_CNT , 0 AS TKEXAM_MNTS , 'N' AS TKEXAM_CMPTNYN , #{item.rgtrId} AS RGTR_ID FROM DUAL
) USR ON ( TKEXAM.EXAM_DTL_ID = USR.EXAM_DTL_ID AND TKEXAM.USER_ID = USR.USER_ID ) WHEN MATCHED THEN UPDATE SET TKEXAM.RETKEXAM_YN = USR.RETKEXAM_YN , TKEXAM.TKEXAM_CNT = USR.TKEXAM_CNT , TKEXAM.TKEXAM_MNTS = USR.TKEXAM_MNTS , TKEXAM.TKEXAM_CMPTNYN = USR.TKEXAM_CMPTNYN , TKEXAM.MDFR_ID = USR.RGTR_ID , TKEXAM.MOD_DTTM = FN_DTTM() WHEN NOT MATCHED THEN INSERT ( TKEXAM_ID , EXAM_DTL_ID , USER_ID , TKEXAM_CNT , TKEXAM_MNTS , TKEXAM_CMPTNYN , RETKEXAM_YN , RGTR_ID , REG_DTTM ) VALUES ( USR.TKEXAM_ID , USR.EXAM_DTL_ID , USR.USER_ID , USR.TKEXAM_CNT , USR.TKEXAM_MNTS , USR.TKEXAM_CMPTNYN , USR.RETKEXAM_YN , USR.RGTR_ID , FN_DTTM() )

		/*
             SQL ID : TkexamDAO.userTkexamRegist
             설  명  : 사용자시험응시등록
         */
        INSERT INTO TB_LMS_TKEXAM (
        	TKEXAM_ID, EXAM_DTL_ID, USER_ID, TKEXAM_CNT, TKEXAM_MNTS, TKEXAM_CMPTNYN, RGTR_ID, REG_DTTM
        ) VALUES (
        	#{tkexamId}, #{examDtlId}, #{userId}, 0, 0, 'N', #{rgtrId}, FN_DTTM()
        )

		/*
             SQL ID : TkexamDAO.userTkexamInit
             설  명  : 사용자시험응시초기화
         */
         UPDATE TB_LMS_TKEXAM SET
         	  MDFR_ID = #{rgtrId}
         	, MOD_DTTM = FN_DTTM()
         	, TKEXAM_CNT = 0
			, TKEXAM_MNTS = 0
			, TKEXAM_CMPTNYN = 'N'
			, TKEXAM_SDTTM = NULL
			, TKEXAM_EDTTM = NULL
          WHERE TKEXAM_ID = #{tkexamId}
		    AND EXAM_DTL_ID = #{examDtlId}
			AND USER_ID = #{userId}

mapper.insert:
/* SQL ID : TkexamDAO.userListTkexamRegist 설 명 : 사용자목록시험응시등록 */ MERGE INTO TB_LMS_TKEXAM TKEXAM USING (
SELECT #{item.tkexamId} AS TKEXAM_ID , #{item.examDtlId} AS EXAM_DTL_ID , #{item.userId} AS USER_ID , 0 AS TKEXAM_CNT , 0 AS TKEXAM_MNTS , 'N' AS TKEXAM_CMPTNYN , #{item.rgtrId} AS RGTR_ID FROM DUAL
) USR ON ( TKEXAM.TKEXAM_ID = USR.TKEXAM_ID AND TKEXAM.EXAM_DTL_ID = USR.EXAM_DTL_ID AND TKEXAM.USER_ID = USR.USER_ID ) WHEN NOT MATCHED THEN INSERT ( TKEXAM_ID , EXAM_DTL_ID , USER_ID , TKEXAM_CNT , TKEXAM_MNTS , TKEXAM_CMPTNYN , RGTR_ID , REG_DTTM ) VALUES ( USR.TKEXAM_ID , USR.EXAM_DTL_ID , USR.USER_ID , USR.TKEXAM_CNT , USR.TKEXAM_MNTS , USR.TKEXAM_CMPTNYN , USR.RGTR_ID , FN_DTTM() )
